mapper.select:
SELECT 
FROM tb_veh_import_event_replay t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.replay_id = #{replayId}


    AND t.veh_import_data_id = #{vehImportDataId}


    AND t.batch_num = #{batchNum}


    AND t.event_type = #{eventType}


    AND t.operator_id = #{operatorId}


    AND t.status = #{status}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}

ORDER BY t.id DESC
